const parseJson = (value) => {
    if (!value) return {}
    if (typeof value === 'object') return value
    const text = String(value).trim()
    if (!text) return {}
    const fenced = text.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i)
    const cleaned = fenced ? fenced[1].trim() : text
    try {
        return JSON.parse(cleaned)
    } catch (error) {
        const start = cleaned.indexOf('{')
        const end = cleaned.lastIndexOf('}')
        if (start !== -1 && end !== -1 && end > start) {
            return JSON.parse(cleaned.slice(start, end + 1))
        }
        throw error
    }
}

const draftRequests = parseJson($draftImageRequests)
const draftResult = parseJson($draftGenerationResult)
const reviewReport = parseJson($reviewReport)

const firstRequest = Array.isArray(draftRequests.requests) && draftRequests.requests.length ? draftRequests.requests[0] : {}
const generatedImages = Array.isArray(draftResult.generatedImages) ? draftResult.generatedImages : []
const firstGenerated = generatedImages.length ? generatedImages[0] : {}
const fileNames = Array.isArray(firstGenerated.fileNames) ? firstGenerated.fileNames.filter(Boolean) : []

if (!fileNames.length) {
    throw new Error('No generated image file name found for refinement')
}

const basePrompt = typeof firstRequest.prompt === 'string' ? firstRequest.prompt.trim() : ''
const refineAddendum = typeof reviewReport.refinePromptAddendum === 'string' ? reviewReport.refinePromptAddendum.trim() : ''
const preserve = Array.isArray(reviewReport.preserve) ? reviewReport.preserve.filter(Boolean) : []
const preserveText = preserve.length ? `保留优点：${preserve.join('；')}` : ''

const refinedPrompt = [
    basePrompt,
    preserveText,
    refineAddendum
].filter(Boolean).join('\n\n')

return {
    requests: [
        {
            prompt: refinedPrompt || basePrompt,
            size: firstRequest.size || '2048x2048',
            outputFormat: firstRequest.outputFormat || 'png',
            watermark: typeof firstRequest.watermark === 'boolean' ? firstRequest.watermark : false,
            referenceImageFileNames: [fileNames[0]]
        }
    ]
}
